import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"圣约裁决·终末福音","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/圣约裁决·终末福音.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/圣约裁决·终末福音.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/圣约裁决·终末福音.md"};function o(_,p,d,l,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"圣约裁决·终末福音",tabindex:"-1"},[t("圣约裁决·终末福音 "),r("a",{class:"header-anchor",href:"#圣约裁决·终末福音","aria-label":'Permalink to "圣约裁决·终末福音"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),n('<h1 id="圣约裁决·终末福音-1" tabindex="-1">圣约裁决·终末福音 <a class="header-anchor" href="#圣约裁决·终末福音-1" aria-label="Permalink to &quot;圣约裁决·终末福音&quot;">​</a></h1><p>圣约裁决·终末福音<br> 于一个满是荒芜，早已了无生气的世界中，拾荒者偶然路过，在众生的尸身堆砌而成的废墟中，至高的心脏蒙尘、纯洁与交织成混浊、血色的羽翼散落、金色与灰色的骨骼交织，侵满血渍的布条束缚，支撑天堂的石柱附着。最后，拾荒者满怀欣喜，他拾走了它。于是一场战争被彻底埋葬、一段悲怆的历史被带走、一场神圣的试炼被后世之人，再度开启。<br> 【注1：若无特殊说明，本资源需差价购买，保留每个等级效果。】<br> 【注2：这是把重机枪。】</p><p>伪典残响<br> 价格：D+500<br> 这把武器如同一具被神圣刑具束缚的野兽，枪体被灰白色亚麻布条层层包裹，布条表面浸透干涸的金色血渍。枪管前端嵌着生锈的铸铁准星，形似倒吊的苦修士铁像。枪管由断裂的教堂青石柱改造，粗粝的石质表面刻满被划花的教廷祷文，看着令人莫名的不安。其上的祷文会加强武器的威能，也能让你以自己的精神力量驱使这把武器。这把武器可以使用【决心+射击：圣约+专注下属辅助专业：亵渎】进行攻击，并在使用它的进行攻击时武器伤害提升等同你的传奇决心*1L。</p><p>但最为奇特的是，被封印在枪托末端的铅制匣子内的不知名物体，仅露出指甲盖大小的六棱截面，透过铅玻璃可见其内部缓慢旋转的灰色星云。它能提供近乎无限的能源，亦为你的身躯带来些许防护，也给你的精神带来意志带来些许压力。因此，你的意志力上限减少2点。这把武器具有无限子弹。也因此，使用者在使用时会莫名的听到一些呢喃声。</p><p>这把武器的武器伤害为8L，具有高速5，贯穿，双手，连射，装弹动作上升一级，弹容量100，基础射程150米。</p><p>逆誓之约<br> 前置：伪典残响<br> 价格：C+1000<br> 随着武器的不断使用，缠绕在其上的布条逐渐燃起，化作灰烬。完全焚毁后，枪械显露出亵渎与神圣交融的狰狞本体——焦黑骨骼与青铜机械拼接的躯干，宛如被剥皮的圣兽骸骨。<br> 封印的圣约之核从铅匣中挣脱，它悬于枪身尾端。表面裂开三道锯齿状缝隙，喷涌出红金双色光流，光流在空气中凝结成逆十字架。<br> 锐利的荆棘遍布了枪身、代替了扳机，堕落的血囊变成装载罪恶的弹匣。</p><p>在枪身上铭刻着一道咒符，意思是“弑神者，必先成为神之镜像。”</p><p>【必要的伤害】：现在，当你进入战斗时，你可以以自由动作，主动握住荆棘遍布的扳机，它不仅会啜饮你的鲜血，也会吞噬吸收你的身体的能量，这会消耗你的3点任意能量以及令你受到1点不可避免的严重伤害。随后，你获得持续一场景的【神圣的救赎/亵渎的背叛】状态。</p><p>【神圣的救赎/亵渎的背叛】：进入该状态后，武器其上的力量部分解放，使你暂时触及这把武器的本质。每当你的回合开始时，你可以选择引导圣约之核之中信仰的力量，金色的屏障环绕在你身边，守护着你，你获得基于本武器的谐振特性，谐振提供偏斜防御，同时额外给予你1点偏斜防御；亦或者，你可以改为接受武器上的无名的堕落力量，激发焦黑的骸骨上极其不详的气息，这会将该武器的武器伤害再提高【传奇决心*2】L，这一效果会替换掉D级带来武器伤害提升的效果影响。</p><p>这把武器的武器伤害为13L 具有高速5，贯穿，双手，连射，装弹动作上升一级，弹容量100，基础射程150米。</p><p>圣骸断罪<br> 前置：逆誓之约<br> 价格：B+3000<br> 这个阶段，其上的荆棘枯萎凋落，它已脱离常规武器范畴，化为光铸刑架与生物兵器的结合体。枪身覆盖猩红血管与焦化羽翼碎片。<br> 圣约之核悬浮脱离枪体，通过光链与使用者心脏连接，能隐约感受到其中，无数无助者、渴求者、虔诚者的祈祷。<br> 枪械的本体亦显现其可怖本质，由七具镀金圣徒骸骨拼接的支架，骸骨上的纹路，由苦难者的无边绝望与愤怒雕刻。<br> 你理解了这把武器背后的意义，你将以神圣之名施行亵渎之实，亦将愈发虔诚的走向逆反的道路。<br> 【已定的命运】：现在，理解了这把武器的真相，也意味着接受了它的力量，它不再是你的阻碍，而是你最强大的助力。现在，在你持用这把武器时，无需为【必要的伤害】支付能量与承受伤害，也可以使用【神圣的救赎/亵渎的背叛】，额外具有【光铸我翼/血造我身】的效果。</p><p>【光铸我翼/血造我身】：在此状态时，因对于武器能力的进一步掌握与理解，在选择使用【神圣的救赎】时，你的身躯会生长出纯白金色的残缺双翼，全身上下散发出神圣的气场，似是要重现当初的第七天使的荣光，而武器上的圣约之核也大放光芒，这令在效果期间你处于格挡状态。在你使用【亵渎的背叛】时，可以为展露它所承载的弑神的威能时，你的全身遍布猩红色的可怖纹路，与七位圣徒骸骨上的纹路连接，充盈毁灭着的力量，弑神的决意会带给阻拦你的敌人以死亡，故在此状态下，你进行的决心相关检定具有9加骰，加骰提升1级（至多8加骰），以此武器进行的攻击会直击对方的灵魂，以极致的苦痛碾压生灵的意志，攻击会以意志豁免来对抗而非防御。</p><p>这把武器的武器伤害为20L，具有高速5，贯穿，双手，连射，装弹动作上升一级，弹容量100，基础射程150米。</p><p>渎神序曲·圣约终章<br> 前置：圣骸断罪<br> 价格：A+4000（单独支付）<br> 在该阶段下，武器以及不再为一个交缠纠错的整体，而是分裂为神圣与亵渎共生的双生形态，悬浮于你身旁两侧，通过数条躺落黑血的光铸锁链与连接你的手臂，脊柱连接。</p><p>左-「圣约终章」<br> 纯白羽翼包裹着的珐琅质天使，看着它似乎是看到了曾经为至高而战的第七天使的圣洁。于瞳孔处，圣约之核分离作半，镶嵌在其上，似是要透过众生虔诚的信仰，展望那极乐的天堂。<br> 以此武器进行格挡时，天使会为需要庇护的众生，需要庇护的你，张开祂洁白神圣的双翼。祂不仅回保护你的身躯，亦是你灵魂最坚实的屏障，你免疫S级诅咒来源的效果。</p><p>右-「渎神默示」<br> 由上千块碎骨、齿轮与圣徒尸骸拼接的可怖恶魔，它的存在象征着背叛神明者最后的疯狂；在中空的身躯中，凝聚着一颗由罪恶与亵渎凝聚而成的恶魔心脏，它已经迫不及待，去完成那弑神的壮举。<br> 在以执行杀戮时，这颗心脏会愈发强烈的跳动，散发出的杀戮之气更是令凡俗胆寒，进行决心相关检定时，你可以将其上的附加成功数转化为检定上的亵渎加值，每1附加可以转化为3DP，最多转化等同你传奇决心*1点附加成功数。祂藐视端坐于至高的祂，唾弃粉饰以爱的苦痛，你免疫S级祝福来源的效果。</p><p>【圣约的终章唱响时】：愈发强大，就愈发与至高的祂更相似，可这也预示着，与祂的决战，已经迫近。现在，你获得【神圣的救赎/亵渎的背叛】【光铸我翼/血造我身】的全部好处，即使在之前等级中这些效果并不能同时存在。你可以以一个移动动作，消耗2点意志开启【逆创世纪·亵渎的颂歌】，【逆创世纪·亵渎的颂歌】提供的效果将持续一场景。</p><p>【逆创世纪·渎神的颂歌】：当初，至高的神曾在创世之时，将万物苏生的喜悦编纂成壮丽的诗篇，可现在祂已经背弃了祂创造的一切。在该状态下，你就可以选择以下的加百列尔曾收集的片段编入你渎神的颂歌，为祂注定的死亡祈祷。当然，背负世界的巨人也会被压弯脊梁，还未跨过人与神的鸿沟的你亦有承载的上限，目前，你引入3个片段，每轮只能从中选择1个片段引入，引入新的片段时会替代旧的片段效果，且无论如何一轮只有一个片段可以生效。每个片段都是世界的一个切片，亦是你誓要弑神的意志体现。</p><p>【杀戮】的片段<br> 十二场流星雨坠入剑鞘<br> 巨人的独眼在血泊中结冰<br> 当英灵殿的横梁长出獠牙<br> 终焉的砝码正是碎裂的恒星<br> 引入这个片段之后，恶魔的拼接骸骨长出可怖的双爪。每轮一次，你的攻击检定出目增加一半处理。</p><p>【消亡】的片段<br> 青铜巨像沉入消逝的海<br> 三枚日轮在龟甲上剥落<br> 锈蚀的王冠压弯冥河摆渡者的脊梁<br> 残破石马拖着王朝的骨灰向西奔逃<br> 引入这个片段之后，天使的眼眶中的圣约之核展现灰白的光辉。这把武器获得【幻灭】特性。</p><p>【权能】的片段<br> 命运跫音，绽开无名之花，<br> 于灰烬之中，神与影子互道衷肠。<br> 这圣契辗转，于绝望者手中传递，<br> 直至那双手，紧握着终极的力量。<br> 引入这个片段之后，你的脑海中将暂时失去所有的感情，似乎是，暂时变化为了，神？使用这把武器进行的攻击检定可以额外加入你的力量属性。</p><p>这把武器的武器伤害为30L，具有高速5，贯穿，双手，连射，装弹动作上升一级，弹容量100，基础射程150米，额外获得2个攻击附加成功数。</p><p>S级 圣约裁决·终末福音<br> 暂不开放。</p><p>掩埋于残破石墙下的历史<br> 10<br> 于幽邃回廊，第七片翎羽自燃成烬，<br> 神之心脏碎裂，化为六面晶莹。<br> 有人将虔诚祷词，铸入恶魔那滚烫髓液，<br> 圣山之巅，裂开第一道神秘痕迹。</p><p>光羽与黑血，交织成同一诗行，<br> 铁誓者掌纹，在封印布条下悄然生根。<br> 准星凝视，仿若倒吊的苦修士身影，<br> 扣动命运扳机，白昼渐次陷入沉寂。</p><p>光芒穿透羽翼，承载起叛逆的重量，<br> 暗匣之中，沉睡的星云缓缓苏醒。<br> 于灰烬深处，燃烧的圣典浮现，<br> 他们口中的试炼，是弑神的暗语。</p><p>白袍掩映下，是铅棺与锁链堆积，<br> 血色天平，称量着圣徒的斑驳骸骨。<br> 焦化羽翼，割裂那跪拜的黄昏，<br> 六棱镜里，聆听着亿万忏悔的回音。</p><p>光铸双翼，却坠向自毁的晨昏，<br> 记忆被锻造成锋利矛锥，<br> 射穿过往荣光，那栖息的蓝枕莺。<br> 当锁链比脊骨更长，第七千滴泪坠入虚空。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',30)])])}const m=b(s,[["render",o]]);export{f as __pageData,m as default};
